  { id: "lark-cli", label: "lark-cli", icon: "\u{1F527}" },
  { id: "sync", label: "\u540C\u6B65", icon: "\u{1F504}" },
  { id: "wiki", label: "\u77E5\u8BC6\u5E93", icon: "\u{1F4DA}" },
  { id: "encoding", label: "\u7F16\u7801\u7CFB\u7EDF", icon: "\u{1F522}" },
  { id: "lark-doc", label: "Lark Doc", icon: "\u{1F4C4}" }
