    const execution = planSyncExecution("push", decision);
    if (execution === "skip") {
      return {
        ok: true,
        action: "skipped",
        hash: parsed.hash,
        title
      };
    }
    if (execution === "advance") {
      await advanceLocalBaseline(deps, file, content, parsed, title);
      return {
        ok: true,
        action: "skipped",
        hash: parsed.hash,
        title
      };
    }
